(function () {
  "use strict";

  // Preloader
  window.addEventListener("load", function () {
    const preloader = document.getElementById("preloader");
    preloader.style.opacity = "0";
    preloader.style.visibility = "hidden";
    setTimeout(() => preloader.remove(), 600);
  });

  // Cursor Glow (Optimized with RAF)
  const cursorGlow = document.getElementById("cursorGlow");
  let ticking = false;
  document.addEventListener("mousemove", (e) => {
    if (!ticking) {
      window.requestAnimationFrame(() => {
        cursorGlow.style.left = e.clientX + "px";
        cursorGlow.style.top = e.clientY + "px";
        ticking = false;
      });
      ticking = true;
    }
  });

  // Particles (Optimized Count)
  const canvas = document.getElementById("particles-canvas");
  const ctx = canvas.getContext("2d");
  let particles = [];
  let animationId;
  let mouseX = 0,
    mouseY = 0;

  // تعریف کلاس Particle قبل از هر استفادهای
  class Particle {
    constructor() {
      this.reset();
    }
    reset() {
      this.x = Math.random() * canvas.width;
      this.y = Math.random() * canvas.height;
      this.size = Math.random() * 2.5 + 0.8;
      this.speedX = (Math.random() - 0.5) * 0.3;
      this.speedY = (Math.random() - 0.5) * 0.3;
      this.opacity = Math.random() * 0.5 + 0.2;
    }
    update() {
      const dx = this.x - mouseX,
        dy = this.y - mouseY;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 150) {
        const force = (150 - dist) / 150;
        this.x += dx * force * 0.01;
        this.y += dy * force * 0.01;
      }
      this.x += this.speedX;
      this.y += this.speedY;
      if (this.x < 0 || this.x > canvas.width) this.speedX *= -0.9;
      if (this.y < 0 || this.y > canvas.height) this.speedY *= -0.9;
      this.x = Math.max(0, Math.min(canvas.width, this.x));
      this.y = Math.max(0, Math.min(canvas.height, this.y));
    }
    draw() {
      ctx.beginPath();
      ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
      const gradient = ctx.createRadialGradient(
        this.x,
        this.y,
        0,
        this.x,
        this.y,
        this.size * 2,
      );
      gradient.addColorStop(0, `rgba(243,190,0,${this.opacity})`);
      gradient.addColorStop(1, "rgba(200,150,0,0)");
      ctx.fillStyle = gradient;
      ctx.fill();
    }
  }

  function resizeCanvas() {
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    initParticles();
  }

  let resizeTimeout;
  window.addEventListener("resize", () => {
    clearTimeout(resizeTimeout);
    resizeTimeout = setTimeout(resizeCanvas, 100);
  });
  resizeCanvas();

  document.addEventListener("mousemove", (e) => {
    mouseX = e.clientX;
    mouseY = e.clientY;
  });

  function initParticles() {
    const isMobile = window.innerWidth < 768;
    const count = isMobile
      ? 40
      : Math.min(100, Math.floor((canvas.width * canvas.height) / 12000));
    particles = Array.from({ length: count }, () => new Particle());
  }

  function connectParticles() {
    for (let i = 0; i < particles.length; i++) {
      for (let j = i + 1; j < particles.length; j++) {
        const dx = particles[i].x - particles[j].x,
          dy = particles[i].y - particles[j].y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < 140) {
          ctx.beginPath();
          ctx.strokeStyle = `rgba(243,190,0,${0.12 * (1 - dist / 140)})`;
          ctx.lineWidth = 0.7;
          ctx.moveTo(particles[i].x, particles[i].y);
          ctx.lineTo(particles[j].x, particles[j].y);
          ctx.stroke();
        }
      }
    }
  }

  function animateParticles() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    particles.forEach((p) => {
      p.update();
      p.draw();
    });
    connectParticles();
    animationId = requestAnimationFrame(animateParticles);
  }
  animateParticles();

  // Navbar Scroll
  const navbar = document.getElementById("navbar");
  window.addEventListener("scroll", () =>
    navbar.classList.toggle("scrolled", window.scrollY > 50),
  );

  // Mobile Nav
  const navToggle = document.getElementById("navToggle");
  const navLinks = document.getElementById("navLinks");
  navToggle.addEventListener("click", () => {
    navToggle.classList.toggle("active");
    navLinks.classList.toggle("open");
  });
  navLinks.querySelectorAll("a").forEach((link) =>
    link.addEventListener("click", () => {
      navToggle.classList.remove("active");
      navLinks.classList.remove("open");
    }),
  );

  // Typed Text
  const typedText = document.getElementById("typedText");
  const phrases = [
    "توسعه‌دهنده فول‌استک",
    "طراح رابط کاربری",
    "عاشق کدنویسی تمیز",
    "متخصص React.js",
    "علاقه‌مند به PHP",
  ];
  let phraseIndex = 0,
    charIndex = 0,
    isDeleting = false;
  function typeEffect() {
    const current = phrases[phraseIndex];
    typedText.textContent = current.substring(0, charIndex);
    if (!isDeleting && charIndex < current.length) {
      charIndex++;
      setTimeout(typeEffect, 90);
    } else if (isDeleting && charIndex > 0) {
      charIndex--;
      setTimeout(typeEffect, 45);
    } else if (!isDeleting && charIndex === current.length) {
      isDeleting = true;
      setTimeout(typeEffect, 1800);
    } else if (isDeleting && charIndex === 0) {
      isDeleting = false;
      phraseIndex = (phraseIndex + 1) % phrases.length;
      setTimeout(typeEffect, 400);
    }
  }
  typeEffect();

  // Reveal
  const revealElements = document.querySelectorAll(".reveal");
  const revealObserver = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          entry.target.classList.add("active");
        }
      });
    },
    { threshold: 0.15 },
  );
  revealElements.forEach((el) => revealObserver.observe(el));

  // Skills Progress
  const skillBars = document.querySelectorAll(".skill-progress");
  const skillObserver = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          entry.target.style.width =
            entry.target.getAttribute("data-width") + "%";
        }
      });
    },
    { threshold: 0.4 },
  );
  skillBars.forEach((bar) => skillObserver.observe(bar));

  // Counter
  const statNumbers = document.querySelectorAll(".stat-number");
  const counterObserver = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          const target = +entry.target.getAttribute("data-target");
          let current = 0;
          const step = Math.ceil(target / 40);
          const timer = setInterval(() => {
            current += step;
            if (current >= target) {
              entry.target.textContent = target + "+";
              clearInterval(timer);
            } else {
              entry.target.textContent = current + "+";
            }
          }, 25);
          counterObserver.unobserve(entry.target);
        }
      });
    },
    { threshold: 0.5 },
  );
  statNumbers.forEach((num) => counterObserver.observe(num));

  // Back to Top
  const backToTop = document.getElementById("backToTop");
  window.addEventListener("scroll", () =>
    backToTop.classList.toggle("visible", window.scrollY > 500),
  );
  backToTop.addEventListener("click", () =>
    window.scrollTo({ top: 0, behavior: "smooth" }),
  );

  // Smooth Scroll
  document.querySelectorAll('a[href^="#"]').forEach((anchor) => {
    anchor.addEventListener("click", function (e) {
      e.preventDefault();
      const target = document.querySelector(this.getAttribute("href"));
      if (target)
        window.scrollTo({
          top: target.getBoundingClientRect().top + window.scrollY - 70,
          behavior: "smooth",
        });
    });
  });

  // Parallax Hero
  window.addEventListener("scroll", () => {
    const heroBg = document.querySelector(".hero-bg-pattern");
    if (heroBg)
      heroBg.style.transform = `translateY(${window.scrollY * 0.2}px)`;
  });
})();
